import WebAudioTinySynth from 'https://cdn.jsdelivr.net/npm/webaudio-tinysynth@1/+esm';
const smf = data.src ? await fetch(data.src).then(r => { if (!r.ok) throw new Error(`MIDI fetch ${r.status}`); return r.arrayBuffer(); }) : null;
async function startFromUserGesture() {
  if (!smf) return null;
  const synth = new WebAudioTinySynth({quality:data.quality ?? 1, voices:data.voices ?? 64, useReverb:(data.useReverb ?? true) ? 1 : 0});
  synth.setMasterVol(data.masterVolume ?? 0.5); synth.loop = (data.loop ?? false) ? 1 : 0;
  await synth.actx.resume(); synth.loadMIDI(smf); synth.playMIDI(); return synth;
}
